<template>
  <div>
    <h3 class="page-title">控制台</h3>
    <el-row :gutter="20">
      <el-col :span="6" v-for="card in cards" :key="card.label">
        <el-card class="stat-card">
          <div class="stat-value">{{ card.value }}</div>
          <div class="stat-label">{{ card.label }}</div>
        </el-card>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import { adminApi } from '../../api';
export default {
  name: 'AdminDashboard',
  data() { return { cards: [] }; },
  created() { this.load(); },
  methods: {
    async load() {
      const res = await adminApi.getStats();
      if (res.code === 200) {
        this.cards = [
          { label: '用户数', value: res.data.userCount },
          { label: '审查记录', value: res.data.reviewCount },
          { label: '问答数', value: res.data.questionCount },
          { label: '学习路径', value: res.data.pathCount }
        ];
      }
    }
  }
};
</script>

<style scoped>
.stat-card { text-align: center; margin-bottom: 20px; }
.stat-value { font-size: 36px; font-weight: bold; color: var(--primary-color); }
.stat-label { font-size: 14px; color: var(--text-secondary); margin-top: 8px; }
</style>
